import Layout from "../layout/Layout";

function Dashboard() {
  return (
    <Layout>
      <h1 className="gradient-text">Placement Dashboard</h1>

      <div style={{ display: "flex", gap: "20px", marginTop: "30px" }}>
        <div className="card">
          <h3>Total Students</h3>
          <h1>120</h1>
        </div>

        <div className="card">
          <h3>Placed</h3>
          <h1>78</h1>
        </div>

        <div className="card">
          <h3>Placement Rate</h3>
          <h1>65%</h1>
        </div>
      </div>
    </Layout>
  );
}

export default Dashboard;
